// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract Whitelist {
    address public owner;
    address[] public whitelist;

    error Unauthorized();

    modifier onlyOwner() {
        [[SLOT owner_guard]]
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function add(address addr) external onlyOwner {
        whitelist.push(addr);
    }

    function clearBatch(uint256 count) external onlyOwner {
        uint256 len = whitelist.length;
        uint256 toRemove = [[SLOT bounded_count]];
        for (uint256 i = 0; i < toRemove; i++) {
            [[SLOT pop_call]]
        }
    }

    function getWhitelist() external view returns (address[] memory) {
        return whitelist;
    }
}
